from dataclasses import dataclass
from typing import Dict

@dataclass
class State:
    total: int = 0
    count: int = 0
    average: float = 0.0

def compute_average(state: State) -> None:
    if state.count > 0:
        state.average = state.total / state.count

def display_results(state: State) -> None:
    print(f"Total: {state.total} Count: {state.count} Average: {state.average:.2f}")

def main() -> None:
    state = State(total=100, count=5)
    compute_average(state)
    display_results(state)

if __name__ == "__main__":
    main()
